import { quote, claim } from "./claim-office.js";

export function runScenario(scenario: any): { results: unknown[] } {
  const results: unknown[] = [];
  let quoteCount = 0;
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const premium = quote({
        customer: {
          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
          previousContracts: quoteCount,
        },
        items: step.items,
      });
      results.push({ premium });
      quoteCount++;
    } else if (step.op === "claim") {
      const { payout, remainingCap } = claim({
        items: scenario.steps[step.policy].items,
        incident: step.incident,
      });
      results.push({ payout, remainingCap });
    }
  }
  return { results };
}
